17	#ifndef ANDROID_ART_RUNTIME_MIRROR_OBJECT_H_
18	#define ANDROID_ART_RUNTIME_MIRROR_OBJECT_H_
19	
20	#include "api/memory_ref.h"
21	
22	struct Object_OffsetTable {
23	    uint32_t klass_;
24	    uint32_t monitor_;
25	};
26	
27	struct Object_SizeTable {
28	    uint32_t THIS;
29	};
30	
31	extern struct Object_OffsetTable __Object_offset__;
32	extern struct Object_SizeTable __Object_size__;
33	
34	namespace art {
35	namespace mirror {
36	
37	class Class;
38	
39	class Object : public api::MemoryRef {
40	public:
41	    Object(uint32_t v) : api::MemoryRef(v) {}
42	    Object(const api::MemoryRef& ref) : api::MemoryRef(ref) {}
43	    Object(uint32_t v, api::MemoryRef& ref) : api::MemoryRef(v, ref) {}
44	    Object(uint32_t v, api::MemoryRef* ref) : api::MemoryRef(v, ref) {}
45	
46	    inline bool operator==(Object& ref) { return Ptr() == ref.Ptr(); }
47	    inline bool operator!=(Object& ref) { return Ptr() != ref.Ptr(); }
48	
49	    static void Init();
50	    inline uint32_t klass() { return *reinterpret_cast<uint32_t*>(Real() + OFFSET(Object, klass_)); }
51	    inline uint32_t monitor() { return *reinterpret_cast<uint32_t*>(Real() + OFFSET(Object, monitor_)); }
52	
53	    Class GetClass();
54	    bool IsClass();
55	    bool IsObjectArray();
56	    bool IsArrayInstance();
57	    bool IsReferenceInstance();
58	    bool IsSpecificPrimitiveArray(uint32_t type);
59	    bool IsBooleanArray();
60	    bool IsByteArray();
61	    bool IsCharArray();
62	    bool IsShortArray();
63	    bool IsIntArray();
64	    bool IsLongArray();
65	    bool IsFloatArray();
66	    bool IsDoubleArray();
67	    bool IsString();
68	    bool IsWeakReferenceInstance();
69	    bool IsSoftReferenceInstance();
70	    bool IsFinalizerReferenceInstance();
71	    bool IsPhantomReferenceInstance();
72	    bool IsClassLoader();
73	    bool IsDexCache();
74	    uint64_t SizeOf();
75	    bool IsValid();
76	    bool IsNonLargeValid();
77	    uint64_t NextValidOffset(uint64_t max);
78	    uint32_t GetLockWord();
79	    uint32_t GetLockOwnerThreadId();
80	private:
81	    // quick memoryref cache
82	    DEFINE_QUICK_CACHE(api::MemoryRef, klass);
83	};
84	
85	} // namespace mirror
86	} // namespace art
87	
88	#endif  // ANDROID_ART_RUNTIME_MIRROR_OBJECT_H_
